import { useEffect, memo } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { setOnBoardingComplete } from '../../reduxStore/actions/flowActions';
import cls from './Login.module.scss';
import { LoginForm } from './LoginForm/LoginForm';
import { isMobile, isSafari } from 'react-device-detect';
import { resetApplication } from '../../services/auth.service';
import { getMasterData } from '../../services/master.service';
import { store } from '../../reduxStore/store';
import { Spinner } from '../common';
import { APP_NAME } from '../../shared/utility';


const Login = memo(() => {
	const navigate = useNavigate();
	const dispatch = useDispatch();
	const { companyData } = store.getState().flowReducer;
	const { authenticated } = store.getState().sessionReducer;

	document.title = `Login-${APP_NAME}`;

	useEffect(() => {
		dispatch(setOnBoardingComplete(false));
		resetApplication();
	}, []);

	return (
		authenticated == false ?
			<div className={cls.host} app-custom-media-show="hide" >
				<div className={cls.firstContainer}>
					<div className={cls.headerTopBarContainer}>
						{APP_NAME}
					</div>
					<div className={cls.firstContainerContent} style={{ width: isMobile ? '70%' : '25%' }}>
						<LoginForm
							onLoginSuccess={() => {


								if (!(companyData?.status === 'trial_ended' || companyData?.status === 'inactive')) {
									getMasterData();
								} else if (companyData?.status === 'inactive') {
									getMasterData(true);
								}
								navigate('/');
							}}
							onResetPassword={() => navigate('/reset-password')}
						/>
					</div>
				</div>
			</div>
			:
			<div className={cls.host}>
				<Spinner size={100} type={'ThreeDots'} />
			</div>

	);
});

export default Login;
